sql:
SELECT COUNT(*) AS total_individual_contributions
FROM contributions
WHERE contb_type = 'individual';

SELECT donor_id, COUNT(contribution_id) AS number_of_donations
FROM contributions
GROUP BY donor_id;

external_knowledge:
- "seeds" metaphorically refer to the potential donors;
- "blossomed into flowers" represents the act of making a contribution;
- "garden of individual donors" refers to donors of the type 'individual';
- "watered their own growth" means the contributions were made by the individuals themselves, as indicated by 'individual' in the contribution type.

sql:
SELECT report_name
FROM reports
WHERE generated_by = 1 AND report_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT donor_type, COUNT(donor_id) AS total_donors
FROM donors
GROUP BY donor_type;

SELECT COUNT(T1.contribution_id) AS total_contributions
FROM contributions AS T1
JOIN major_contributors AS T2 ON T1.donor_id = T2.donor_id;

SELECT donor_id 
FROM major_contributors 
WHERE total_amt > (SELECT SUM(contb_amt) FROM contributions WHERE contb_amt > 500);

SELECT SUM(contb_amt) AS total_contributed
FROM contributions
WHERE donor_id = 1;

SELECT SUM(contb_amt) AS total_contributions
FROM contributions
WHERE receipt_dt BETWEEN '2022-01-01' AND '2022-12-31';

SELECT COUNT(DISTINCT mc.donor_id) AS count_major_contributors_with_recurring
FROM major_contributors mc
INNER JOIN recurring_donors rd ON mc.donor_id = rd.donor_id;

SELECT donor_id, AVG(contb_amt) AS average_contribution
FROM contributions
GROUP BY donor_id;
